/* ═══════════════════════════════════════════════════════════════════════════
   Contributor Network — Live distributed worker dashboard
   Wired to /api/cluster/contributor/* (leaderboard, stats, auto-provision)
   ═══════════════════════════════════════════════════════════════════════════ */
import { useState, useEffect, useCallback, useRef } from 'react';
import { motion } from 'framer-motion';
import { api } from '../utils/api';
import usePageTitle from '../hooks/usePageTitle';
import s from './ContributorDashboardPage.module.css';

function MetricCard({ label, value, sub, color }) {
  return (
    <div className={s.metricCard}>
      <div className={s.metricLabel}>{label}</div>
      <div className={s.metricValue} style={{ color: color || 'var(--color-text, #E5E7DB)' }}>
        {value}
      </div>
      {sub && <div className={s.metricSub}>{sub}</div>}
    </div>
  );
}

function ProgressBar({ completed, total, label }) {
  const pct = total > 0 ? Math.min((completed / total) * 100, 100) : 0;
  return (
    <div className={s.progressContainer}>
      <div className={s.progressHeader}>
        <span className={s.progressLabel}>{label || 'Progress'}</span>
        <span className={s.progressValue}>
          {completed.toLocaleString()} / {total.toLocaleString()} ({pct.toFixed(1)}%)
        </span>
      </div>
      <div className={s.progressTrack}>
        <motion.div
          className={s.progressFill}
          initial={{ width: 0 }}
          animate={{ width: `${pct}%` }}
          transition={{ duration: 0.6, ease: 'easeOut' }}
        />
      </div>
    </div>
  );
}

function workerColor(status) {
  if (status === 'online') return 'var(--color-green, #22C55E)';
  if (status === 'busy') return 'var(--color-cyan, #36BDF0)';
  return 'var(--color-red, #EF4444)';
}

function timeAgo(ts) {
  if (!ts) return '--';
  const diff = Math.max(0, Date.now() - new Date(ts + (ts.includes('Z') || ts.includes('+') ? '' : 'Z')).getTime());
  const mins = Math.floor(diff / 60000);
  if (mins < 1) return 'just now';
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  return `${Math.floor(hrs / 24)}d ago`;
}

const DAILY_TARGET = 50_000;

// ═════════════════════════════════════════════════════════════════════════════
export default function ContributorDashboardPage() {
  usePageTitle('Contributor Network');

  const [leaderboard, setLeaderboard] = useState(null);
  const [gridStatus, setGridStatus] = useState(null);
  const [jobTypes, setJobTypes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [copied, setCopied] = useState(false);

  const [prevCompleted, setPrevCompleted] = useState(0);
  const [throughput, setThroughput] = useState(0);
  const prevTimeRef = useRef(Date.now());

  // ── Fetch ──────────────────────────────────────────────────────────────────
  const fetchData = useCallback(async () => {
    const [lbRes, statusRes, jtRes] = await Promise.all([
      api('/cluster/contributor/leaderboard?limit=30', { silent: true }),
      api('/intelligence/status', { silent: true }),
      api('/cluster/contributor/job-types', { silent: true }),
    ]);
    if (lbRes) setLeaderboard(lbRes);
    if (statusRes) setGridStatus(statusRes);
    if (jtRes) setJobTypes(jtRes.job_types || []);
    setLoading(false);
  }, []);

  useEffect(() => {
    fetchData();
    const iv = setInterval(fetchData, 5000);
    return () => clearInterval(iv);
  }, [fetchData]);

  // ── Derived ────────────────────────────────────────────────────────────────
  const grid = leaderboard?.grid_totals || {};
  const entries = leaderboard?.leaderboard || [];
  const jobsByStatus = gridStatus?.jobs_by_status || {};
  const completed = jobsByStatus.completed || 0;
  const queued = jobsByStatus.queued || 0;
  const leased = jobsByStatus.leased || 0;

  useEffect(() => {
    if (completed > prevCompleted && prevCompleted > 0) {
      const now = Date.now();
      const elapsedSec = Math.max(1, (now - prevTimeRef.current) / 1000);
      const rate = ((completed - prevCompleted) / elapsedSec) * 3600;
      setThroughput(prev => prev > 0 ? Math.round(prev * 0.7 + rate * 0.3) : Math.round(rate));
      prevTimeRef.current = now;
    }
    setPrevCompleted(completed);
  }, [completed]); // eslint-disable-line react-hooks/exhaustive-deps

  const displayThroughput = throughput > 0 ? throughput : (gridStatus?.throughput_1h || 0);

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(
        'python -m distributed_research.standalone --coordinator-url https://auraalpha.cc --token YOUR_TOKEN'
      );
      setCopied(true);
      setTimeout(() => setCopied(false), 2500);
    } catch { setCopied(false); }
  };

  if (loading) {
    return (
      <div className={s.loading}>
        <div className={s.loadingText}>
          Connecting to contributor network...
        </div>
      </div>
    );
  }

  return (
    <motion.div
      initial={{ opacity: 0, y: 12 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.35 }}
      className={s.page}
    >
      {/* ── Header ──────────────────────────────────────────────────────────── */}
      <div className={s.header}>
        <h1 className={s.title}>Contributor Network</h1>
        <span
          className={s.onlineBadge}
          style={{
            background: grid.online_now > 0 ? '#1a2e1a' : '#2e1a1a',
            border: `1px solid ${grid.online_now > 0
              ? 'color-mix(in srgb, var(--color-green, #22C55E) 40%, transparent)'
              : 'color-mix(in srgb, var(--color-red, #EF4444) 40%, transparent)'}`,
            color: grid.online_now > 0
              ? 'var(--color-green, #22C55E)'
              : 'var(--color-red, #EF4444)',
          }}
        >
          {grid.online_now > 0 ? `${grid.online_now} online` : 'no workers online'}
        </span>
      </div>

      {/* ── Stats Bar ───────────────────────────────────────────────────────── */}
      <div className={s.statsBar}>
        <MetricCard
          label="Contributors"
          value={grid.total_contributors || 0}
          sub={`${grid.online_now || 0} online now`}
          color="var(--color-cyan, #36BDF0)"
        />
        <MetricCard
          label="Throughput"
          value={displayThroughput > 0 ? displayThroughput.toLocaleString() : '--'}
          sub="jobs / hour"
          color="var(--color-blue, #60A5FA)"
        />
        <MetricCard
          label="Total Completed"
          value={(grid.total_jobs_completed || completed || 0).toLocaleString()}
          sub="all-time"
          color="var(--color-green, #22C55E)"
        />
        <MetricCard
          label="Compute Donated"
          value={`${grid.total_compute_hours || 0}h`}
          sub={`${grid.total_cpu_cores || 0} cores`}
          color="var(--color-purple, #A78BFA)"
        />
        <MetricCard
          label="Queue"
          value={queued.toLocaleString()}
          sub={`${leased} processing`}
          color={queued > 0 ? 'var(--color-amber, #F59E0B)' : 'var(--color-text-secondary, #90A3AF)'}
        />
      </div>

      {/* ── Daily Progress ────────────────────────────────────────────────── */}
      <ProgressBar
        completed={(grid.total_jobs_completed || completed) % DAILY_TARGET}
        total={DAILY_TARGET}
        label="Daily Target"
      />

      {/* ── Job Types Available ────────────────────────────────────────────── */}
      {jobTypes.length > 0 && (
        <div className={s.section}>
          <div className={s.sectionTitle}>Distributed Job Types</div>
          <div className={s.jobTypesGrid}>
            {jobTypes.map((jt) => (
              <div key={jt.type} className={s.jobTypeCard}>
                <div className={s.jobTypeName}>{jt.type}</div>
                <div className={s.jobTypeDesc}>{jt.description}</div>
                <div className={s.jobTypeDuration}>~{jt.avg_duration_seconds}s avg</div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* ── Leaderboard ───────────────────────────────────────────────────── */}
      <div className={s.sectionOverflow}>
        <div className={s.sectionTitle}>
          Contributor Leaderboard ({entries.length})
        </div>
        {entries.length === 0 ? (
          <div className={s.emptyState}>No contributors yet</div>
        ) : (
          <table className={s.table}>
            <thead>
              <tr>
                <th className={s.thRank}>#</th>
                <th className={s.thLeft}>Worker</th>
                <th className={s.thLeft}>Type</th>
                <th className={s.thRight}>Status</th>
                <th className={s.thRight}>Jobs</th>
                <th className={s.thRight}>Failed</th>
                <th className={s.thRight}>Compute</th>
                <th className={s.thRight}>Cores</th>
                <th className={s.thRight}>RAM</th>
                <th className={s.thRight}>Last Seen</th>
              </tr>
            </thead>
            <tbody>
              {entries.map((e, i) => (
                <tr key={i} className={s.tr}>
                  <td className={s.tdCenter}>{e.rank}</td>
                  <td className={s.tdWorker}>{e.hostname || e.worker_id}</td>
                  <td className={s.tdType}>{e.worker_type || '--'}</td>
                  <td className={s.tdRight}>
                    <span className={s.statusLabel} style={{ color: workerColor(e.status) }}>
                      {e.status}
                    </span>
                  </td>
                  <td className={s.tdJobs}>{(e.jobs_completed || 0).toLocaleString()}</td>
                  <td className={s.tdRight} style={{ color: (e.jobs_failed || 0) > 0 ? 'var(--color-red, #EF4444)' : 'var(--color-text-secondary, #90A3AF)' }}>
                    {(e.jobs_failed || 0).toLocaleString()}
                  </td>
                  <td className={s.tdCompute}>{e.compute_hours}h</td>
                  <td className={s.tdCores}>{e.cpu_count}</td>
                  <td className={s.tdSecondary}>{e.ram_gb}GB</td>
                  <td className={s.tdSecondary}>{timeAgo(e.last_seen)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      {/* ── Get Started ───────────────────────────────────────────────────── */}
      <div className={s.joinSection}>
        <div className={s.joinTitle}>Join the Network</div>
        <div className={s.joinDesc}>
          Contribute compute from any machine running the Aura Alpha Desktop app.
          Workers auto-provision, pull jobs from the queue, run backtests locally, and report results back.
        </div>
        <div className={s.cliSection}>
          <div className={s.cliLabel}>Manual Setup (CLI)</div>
          <div className={s.cliRow}>
            <code className={s.cliCode}>
              python -m distributed_research.standalone --coordinator-url https://auraalpha.cc --token YOUR_TOKEN
            </code>
            <button
              onClick={handleCopy}
              className={s.copyBtn}
              style={{
                background: copied
                  ? 'color-mix(in srgb, var(--color-green, #22C55E) 10%, transparent)'
                  : 'var(--color-surface2, #141C28)',
                border: `1px solid ${copied
                  ? 'color-mix(in srgb, var(--color-green, #22C55E) 27%, transparent)'
                  : 'var(--color-border, #1F2A37)'}`,
                color: copied
                  ? 'var(--color-green, #22C55E)'
                  : 'var(--color-text, #E5E7DB)',
              }}
            >
              {copied ? 'Copied!' : 'Copy'}
            </button>
          </div>
        </div>
        <div className={s.footerNote}>
          <span className={s.footerDot} />
          Desktop app auto-provisions tokens -- no manual setup needed
        </div>
      </div>
    </motion.div>
  );
}
